#include <stdio.h>
#include <stdlib.h>

#define N 101

// Structure for adjacency list node
struct Node {
    int vertex;
    struct Node* next;
};

// Array of adjacency lists
struct Node* adj[N];

// Array to keep track of visited nodes
int vis[N];

// Array to keep track of node colors
int color[N];

// Function to create a new adjacency list node
struct Node* createNode(int v) {
    struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
    newNode->vertex = v;
    newNode->next = NULL;
    return newNode;
}

// Function to add an edge to an undirected graph
void addEdge(int src, int dest) {
    struct Node* newNode = createNode(dest);
    newNode->next = adj[src];
    adj[src] = newNode;

    newNode = createNode(src);
    newNode->next = adj[dest];
    adj[dest] = newNode;
}

// Depth First Search function
void dfs(int v, int col) {
    if (vis[v]) {
        return; // If the node is already visited, do not process it
    }
    vis[v] = 1; // Mark the node as visited
    color[v] = col; // Color the node

    struct Node* temp = adj[v];
    while (temp) {
        int u = temp->vertex;
        dfs(u, col);
        temp = temp->next;
    }
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);

        // Resetting the adjacency list, color, and visited array
        for (int i = 0; i <= n; i++) {
            struct Node* temp = adj[i];
            while (temp) {
                struct Node* next = temp->next;
                free(temp);
                temp = next;
            }
            adj[i] = NULL;
            color[i] = 0;
            vis[i] = 0;
        }

        for (int i = 1; i <= m; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            addEdge(x, y);
        }

        int current = 1;
        for (int i = 0; i < n; i++) {
            if (!vis[i]) {
                // Color all the nodes connected with i
                // with the same color
                dfs(i, current);
                current++;
            }
        }

        // Two connected places will now have the same color

        int q;
        scanf("%d", &q);
        while (q--) {
            int x, y;
            scanf("%d %d", &x, &y);

            // Output "YO" if both nodes have the same color
            if (color[x] == color[y]) {
                printf("YO\n");
            } else {
                printf("NO\n");
            }
        }
    }
    return 0;
}

