import java.util.*;

class main {
    static int N = 101;
    static List<Integer>[] adj = new ArrayList[N];
    static int[] vis = new int[N];
    static int[] color = new int[N];

    public static void dfs(int v, int col) {
        if (vis[v] == 1)
            return;

        vis[v] = 1;
        color[v] = col;

        for (int x : adj[v]) {
            dfs(x, col);
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt(); 

        while (t-- > 0) {
            int n = scanner.nextInt(); 
            int m = scanner.nextInt(); 

            for (int i = 0; i <= n; i++) {
                adj[i] = new ArrayList<>();
                color[i] = 0;
                vis[i] = 0;
            }

            // Creating the graph
            for (int i = 1; i <= m; i++) {
                int x = scanner.nextInt();
                int y = scanner.nextInt();
                adj[x].add(y);
                adj[y].add(x);
            }

            int current = 1;
            for (int i = 0; i < n; i++) {
                if (vis[i] == 0) {
                    // Color all the connected nodes with the same color
                    dfs(i, current);
                    current++;
                }
            }

            int q = scanner.nextInt(); 

            // Checking if nodes have the same color
            while (q-- > 0) {
                int x = scanner.nextInt();
                int y = scanner.nextInt();

                if (color[x] == color[y]) {
                    System.out.println("YO");
                } else {
                    System.out.println("NO");
                }
            }
        }
    }
}
